1	import mongoose, { Schema, Document, Model } from 'mongoose';
2	import { INodeLessonContent, ICanonicalNodeLesson } from '../types/roadmap.types';
3	
4	/**
5	 * NODE LESSON CONTENT
6	 * Кэш сгенерированного (AI-консолидированного) контента урока узла КТП.
7	 * Граф роудмапа строится вживую из КТП; контент урока — генерируется один раз и кэшируется здесь.
8	 * Инвалидация по sourceHash (хэш текстов замапленных тем книг).
9	 */
10	
11	const StoredLessonSchema = new Schema<ICanonicalNodeLesson>(
12	  {
13	    lessonId: { type: String, required: true },
14	    title: { type: String, required: true },
15	    order: { type: Number, required: true },
16	    content: { type: String, required: true },
17	    contentFormat: { type: String, enum: ['markdown', 'html'], default: 'markdown' },
18	    summary: { type: String }
19	  },
20	  { _id: false }
21	);
22	
23	type Doc = Document & Omit<INodeLessonContent, '_id'>;
24	
25	const NodeLessonContentSchema = new Schema<Doc>(
26	  {
27	    subjectId: { type: Schema.Types.ObjectId, ref: 'Subject', required: true, index: true },
28	    ktpTopicId: { type: Schema.Types.ObjectId, required: true },
29	    sourceHash: { type: String, required: true },
30	    lessons: { type: [StoredLessonSchema], default: [] },
31	    generatedBy: { type: String, enum: ['ai', 'manual'], default: 'ai' }
32	  },
33	  { timestamps: true, collection: 'node_lesson_content' }
34	);
35	
36	NodeLessonContentSchema.index({ subjectId: 1, ktpTopicId: 1 }, { unique: true });
37	
38	export const NodeLessonContent: Model<Doc> = mongoose.model<Doc>(
39	  'NodeLessonContent',
40	  NodeLessonContentSchema
41	);
