1	import { createHash } from 'crypto';
2	import { NodeLessonContent } from '../models/NodeLessonContent.model';
3	import {
4	  ICanonicalRoadmapNode,
5	  ICanonicalNodeLesson,
6	  ICanonicalNodeSource,
7	  IRoadmapLessonSource
8	} from '../types/roadmap.types';
9	import { getNodeLessons } from '../utils/nodeLessons.util';
10	import { extractTopicText } from '../utils/roadmapChapter.util';
11	import { roadmapAIService } from './roadmap.ai.service';
12	
13	type SubjectShape = {
14	  title?: string;
15	  books?: Array<{ _id?: { toString(): string }; title?: string }>;
16	};
17	
18	function nodeKtpTopicId(node: ICanonicalRoadmapNode): string | null {
19	  const md = node.metadata as Record<string, unknown> | undefined;
20	  const id = md && typeof md.ktpTopicId === 'string' ? md.ktpTopicId : undefined;
21	  return id ?? null;
22	}
23	
24	function nodeSources(node: ICanonicalRoadmapNode): ICanonicalNodeSource[] {
25	  const md = node.metadata as Record<string, unknown> | undefined;
26	  const arr = md?.sources;
27	  return Array.isArray(arr) ? (arr as ICanonicalNodeSource[]) : [];
28	}
29	
30	function bookTitleOf(subject: SubjectShape, bookId: string): string | undefined {
31	  return subject.books?.find((b) => b._id?.toString() === bookId)?.title;
32	}
33	
34	/** Источники узла с метками и текстами (для AI-консолидации). */
35	function sourcesWithText(
36	  subject: unknown,
37	  sources: ICanonicalNodeSource[]
38	): Array<{ source: ICanonicalNodeSource; label: string; text: string }> {
39	  const sub = subject as SubjectShape;
40	  return sources
41	    .map((s) => {
42	      const bookTitle = bookTitleOf(sub, s.bookId) || 'Книга';
43	      const label = s.title ? `${bookTitle} · ${s.title}` : bookTitle;
44	      const text = extractTopicText(subject, s.bookId, s.chapterId, s.topicId) || s.title || '';
45	      return { source: s, label, text };
46	    })
47	    .filter((x) => x.text.trim());
48	}
49	
50	function computeSourceHash(items: Array<{ topicId: string; text: string }>): string {
51	  return createHash('sha256').update(JSON.stringify(items.map((i) => [i.topicId, i.text]))).digest('hex');
52	}
53	
54	function storedToLessons(row: { lessons?: ICanonicalNodeLesson[] }): ICanonicalNodeLesson[] {
55	  return [...(row.lessons ?? [])]
56	    .map((l) => ({
57	      lessonId: l.lessonId,
58	      title: l.title,
59	      order: l.order,
60	      content: l.content,
61	      contentFormat: l.contentFormat === 'html' ? ('html' as const) : ('markdown' as const),
62	      ...(l.summary ? { summary: l.summary } : {}),
63	      video: null
64	    }))
65	    .sort((a, b) => a.order - b.order);
66	}
67	
68	/** Описание источников узла для UI (книга/класс + тема), без текстов. */
69	export function describeNodeSources(subject: unknown, node: ICanonicalRoadmapNode): IRoadmapLessonSource[] {
70	  const sub = subject as SubjectShape;
71	  return nodeSources(node).map((s) => ({
72	    ...(bookTitleOf(sub, s.bookId) ? { bookTitle: bookTitleOf(sub, s.bookId) } : {}),
73	    ...(s.title ? { topicTitle: s.title } : {})
74	  }));
75	}
