40	/** Сохранить summary урока в сохранённый документ карты (только для не-live карт). */
41	async function persistLessonSummary(
42	  subjectId: string,
43	  nodeId: string,
44	  lessonId: string,
45	  summary: string
46	): Promise<void> {
47	  if (await isLiveBuiltFromKtp(subjectId)) return;
48	
49	  const subjectOid = new mongoose.Types.ObjectId(subjectId);
50	  const doc = await CanonicalRoadmap.findOne({ subjectId: subjectOid }).sort({ version: -1 });
51	  if (!doc) return;
52	
53	  const updatedNodes = doc.nodes.map((n) => {
54	    if (n.nodeId !== nodeId) return n;
55	    const meta =
56	      n.metadata && typeof n.metadata === 'object' && n.metadata !== null
57	        ? { ...(n.metadata as Record<string, unknown>) }
58	        : {};
59	
60	    // metadata.lessons[] — обновляем урок по lessonId
61	    if (Array.isArray(meta.lessons)) {
62	      meta.lessons = (meta.lessons as Array<Record<string, unknown>>).map((l) =>
63	        l && l.lessonId === lessonId ? { ...l, summary } : l
64	      );
65	    }
66	    // single metadata.lesson — обратная совместимость
67	    if (meta.lesson && typeof meta.lesson === 'object' && !Array.isArray(meta.lesson)) {
68	      const oldLesson = meta.lesson as Record<string, unknown>;
69	      if (!oldLesson.lessonId || oldLesson.lessonId === lessonId) {
70	        meta.lesson = { ...oldLesson, summary };
71	      }
72	    }
73	    return { ...n, metadata: meta };
74	  });
75	
76	  doc.set('nodes', updatedNodes);
77	  doc.markModified('nodes');
78	  await doc.save();
79	}
